#include <bits/stdc++.h>
using namespace std;
long long xorUpto(long long n){
    switch(n & 3LL){
        case 0: return n;
        case 1: return 1;
        case 2: return n+1;
        default: return 0;
    }
}
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    long long left, right;
    if(!(cin>>left)) return 0;
    if(!(cin>>right)) return 0;
    long long result = xorUpto(right) ^ xorUpto(left-1);
    cout<<result;
    return 0;
}
